1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	type Item = { type: string };
5	
6	type Scenario = {
7	  customer: { yearsWithMHPCO: number };
8	  steps: { op: string; items?: Item[] }[];
9	};
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	};
15	
16	const itemBase = (item: Item): number => BASE_PREMIUMS[item.type];
17	
18	const quotePremium = (items: Item[]): number => {
19	  if (items.length === 0) return PROCESSING_FEE;
20	  const policyBase = items.reduce((sum, it) => sum + itemBase(it), 0);
21	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
22	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
23	};
24	
25	export const runScenario = (input: unknown): unknown => {
26	  const scenario = input as Scenario;
27	  const results = scenario.steps.map((step) => ({
28	    premium: quotePremium(step.items ?? []),
29	  }));
30	  return { results };
31	};
